const body = $input.item.json.body;
const showroomUuid = (body.showroomUuid || '').trim();
if (!showroomUuid || !/^[0-9a-f-]{36}$/i.test(showroomUuid)) {
  throw new Error('Missing or invalid showroomUuid in request body');
}
return [{ json: { showroomUuid } }];

const resp = $input.item.json;
if (!resp.success || !resp.response) {
  throw new Error(`Failed to fetch showroom: ${JSON.stringify(resp.errors)}`);
}

const showroom = resp.response;
const showroomName = showroom.name || 'Showroom';
const groups = showroom.groups || [];
const products = showroom.products || showroom.productsUuids || [];

// Build a flat list: try to get name + uuid from each product entry
const rows = [];
if (groups.length > 0) {
  groups.forEach(g => {
    (g.productsInfo || []).forEach(p => {
      rows.push({
        uuid: p.productUuid || p.uuid || '',
        name: p.productName || p.name || '',
        group: g.title || '',
        order: p.order ?? '',
      });
    });
  });
} else {
  // Fallback: flat productsUuids array
  products.forEach((p, i) => {
    const uuid = typeof p === 'string' ? p : (p.uuid || p.productUuid || '');
    rows.push({ uuid, name: typeof p === 'object' ? (p.name || '') : '', group: '', order: i + 1 });
  });
}

// Build CSV
const csvLines = ['Asset UUID,Asset Name,Group,Order'];
rows.forEach(r => {
  const name  = String(r.name  || '').replace(/,/g, ' ');
  const group = String(r.group || '').replace(/,/g, ' ');
  csvLines.push(`${r.uuid},${name},${group},${r.order}`);
});

const csv = csvLines.join('\n');
const filename = `${showroomName.replace(/[^a-zA-Z0-9 _-]/g, '')} — Assets.csv`;

return [{ json: { csv, filename, showroomName, count: rows.length } }];

const { csv, filename } = $input.item.json;
const base64 = Buffer.from(csv, 'utf8').toString('base64');
return [{
  json: $input.item.json,
  binary: {
    data: {
      data: base64,
      mimeType: 'text/csv',
      fileName: filename,
    }
  }
}];
